from pathlib import Pathfrom langchain_openai import OpenAIEmbeddingsfrom langchain_qdrant import QdrantVectorStorefrom qdrant_client import QdrantClientfrom rag_chatbot.config import (    PDF_FILE,    QDRANT_PATH,    COLLECTION_NAME,    EMBEDDING_MODEL,    BASE_DIR,)from rag_chatbot.loaders import load_pdf, load_languages_jsonfrom rag_chatbot.cleaners import clean_textfrom rag_chatbot.chunkers import chunk_faq_documentsdef deduplicate_chunks(chunks):    seen = set()    unique = []    for chunk in chunks:        key = (            chunk.metadata.get("doc_type"),            chunk.metadata.get("section"),            chunk.metadata.get("question"),            chunk.page_content.strip(),        )        if key not in seen:            seen.add(key)            unique.append(chunk)    return uniquedef ingest():    pdf_docs = load_pdf(str(PDF_FILE))    for doc in pdf_docs:        doc.page_content = clean_text(doc.page_content)        doc.metadata["source"] = "Tallinna Keeltekooli KKK"        doc.metadata["doc_type"] = "faq"    faq_chunks = chunk_faq_documents(pdf_docs)    structured_docs = load_languages_json(        str(BASE_DIR / "data" / "structured" / "languages.json")    )    all_docs = faq_chunks + structured_docs    all_docs = deduplicate_chunks(all_docs)    client = QdrantClient(path=str(QDRANT_PATH))    if client.collection_exists(COLLECTION_NAME):        client.delete_collection(COLLECTION_NAME)    embeddings = OpenAIEmbeddings(model=EMBEDDING_MODEL)    QdrantVectorStore.from_documents(        documents=all_docs,        embedding=embeddings,        path=str(QDRANT_PATH),        collection_name=COLLECTION_NAME,    )    print(f"Ingest valmis. Salvestati {len(all_docs)} dokumenti/chunki Qdranti.")if __name__ == "__main__":    ingest()